    45→func ProvideService(
    46→	cfg *setting.Cfg,
    47→	dataSourceCache datasources.CacheService,
    48→	expressionService *expr.Service,
    49→	dataSourceRequestValidator validations.DataSourceRequestValidator,
    50→	pluginClient plugins.Client,
