    69→//go:generate mockery --name Service --structname FakeQueryService --inpackage --filename query_service_mock.go
    70→type Service interface {
    71→	Run(ctx context.Context) error
    72→	QueryData(ctx context.Context, user identity.Requester, skipDSCache bool, reqDTO dtos.MetricRequest) (*backend.QueryDataResponse, error)
    73→
    74→	// this is more "forward compatible", for example supports per-query time ranges
    75→	QueryDataNew(ctx context.Context, user identity.Requester, skipDSCache bool, reqDTO dtos.MetricRequest) (*backend.QueryDataResponse, error)
    76→}
    77→
    78→// Gives us compile time error if the service does not adhere to the contract of the interface
    79→var _ Service = (*ServiceImpl)(nil)
    80→
    81→type ServiceImpl struct {
    82→	cfg                        *setting.Cfg
    83→	dataSourceCache            datasources.CacheService
    84→	expressionService          *expr.Service
    85→	dataSourceRequestValidator validations.DataSourceRequestValidator
    86→	pluginClient               plugins.Client
    87→	pCtxProvider               *plugincontext.Provider
    88→	log                        log.Logger
    89→	concurrentQueryLimit       int
    90→	qsDatasourceClientBuilder  dsquerierclient.QSDatasourceClientBuilder
    91→	headers                    map[string]string
    92→}
    93→
    94→// Run ServiceImpl.
    95→func (s *ServiceImpl) Run(ctx context.Context) error {
    96→	<-ctx.Done()
    97→	return ctx.Err()
    98→}
    99→
   100→// QueryData processes queries and returns query responses. It handles queries to single or mixed datasources, as well as expressions.
   101→func (s *ServiceImpl) queryData(ctx context.Context, user identity.Requester, skipDSCache bool, reqDTO dtos.MetricRequest, supportLocaltimeRange bool) (*backend.QueryDataResponse, error) {
   102→	fromAlert := false
   103→	for header, val := range s.headers {
   104→		if header == models.FromAlertHeaderName && val == "true" {
   105→			fromAlert = true
   106→		}
   107→	}
   108→	// Parse the request into parsed queries grouped by datasource uid
   109→	parsedReq, err := s.parseMetricRequest(ctx, user, skipDSCache, reqDTO, supportLocaltimeRange)
   110→	if err != nil {
   111→		return nil, err
   112→	}
   113→
   114→	// If there are expressions, handle them and return
   115→	if parsedReq.hasExpression || fromAlert {
   116→		return s.handleExpressions(ctx, user, parsedReq)
   117→	}
   118→	// If there is only one datasource, query it and return
   119→	if len(parsedReq.parsedQueries) == 1 {
   120→		return s.handleQuerySingleDatasource(ctx, user, parsedReq)
   121→	}
   122→	// If there are multiple datasources, handle their queries concurrently and return the aggregate result
   123→	return s.executeConcurrentQueries(ctx, user, skipDSCache, reqDTO, parsedReq.parsedQueries)
   124→}
   125→
   126→func (s *ServiceImpl) QueryData(ctx context.Context, user identity.Requester, skipDSCache bool, reqDTO dtos.MetricRequest) (*backend.QueryDataResponse, error) {
   127→	return s.queryData(ctx, user, skipDSCache, reqDTO, false)
   128→}
   129→
   130→func (s *ServiceImpl) QueryDataNew(ctx context.Context, user identity.Requester, skipDSCache bool, reqDTO dtos.MetricRequest) (*backend.QueryDataResponse, error) {
   131→	return s.queryData(ctx, user, skipDSCache, reqDTO, true)
   132→}
   133→
   134→// splitResponse contains the results of a concurrent data source query - the response and any headers
   135→type splitResponse struct {
   136→	responses backend.Responses
   137→	header    http.Header
   138→}
   139→
   140→// executeConcurrentQueries executes queries to multiple datasources concurrently and returns the aggregate result.
   141→func (s *ServiceImpl) executeConcurrentQueries(ctx context.Context, user identity.Requester, skipDSCache bool, reqDTO dtos.MetricRequest, queriesbyDs map[string][]parsedQuery) (*backend.QueryDataResponse, error) {
   142→	g, ctx := errgroup.WithContext(ctx)
   143→	g.SetLimit(s.concurrentQueryLimit) // prevent too many concurrent requests
   144→	rchan := make(chan splitResponse, len(queriesbyDs))
   145→
   146→	// Create panic recovery function for loop below
   147→	recoveryFn := func(queries []*simplejson.Json) {
   148→		if r := recover(); r != nil {
   149→			var err error
   150→			s.log.Error("query datasource panic", "error", r, "stack", log.Stack(1))
   151→			if theErr, ok := r.(error); ok {
   152→				err = theErr
   153→			} else if theErrString, ok := r.(string); ok {
   154→				err = errors.New(theErrString)
   155→			} else {
   156→				err = fmt.Errorf("unexpected error - %s", s.cfg.UserFacingDefaultError)
   157→			}
   158→			// Due to the panic, there is no valid response for any query for this datasource. Append an error for each one.
   159→			rchan <- buildErrorResponses(err, queries)
   160→		}
   161→	}
   162→
   163→	// Query each datasource concurrently
   164→	for _, queries := range queriesbyDs {
   165→		rawQueries := make([]*simplejson.Json, len(queries))
   166→		for i := 0; i < len(queries); i++ {
   167→			rawQueries[i] = queries[i].rawQuery
   168→		}
   169→		g.Go(func() error {
   170→			subDTO := reqDTO.CloneWithQueries(rawQueries)
   171→			// Handle panics in the datasource qery
   172→			defer recoveryFn(subDTO.Queries)
   173→
   174→			ctxCopy := contexthandler.CopyWithReqContext(ctx)
   175→			subResp, err := s.QueryData(ctxCopy, user, skipDSCache, subDTO)
   176→			if err == nil {
   177→				reqCtx, header := contexthandler.FromContext(ctxCopy), http.Header{}
   178→				if reqCtx != nil {
   179→					header = reqCtx.Resp.Header()
   180→				}
   181→				rchan <- splitResponse{subResp.Responses, header}
   182→			} else {
   183→				// If there was an error, return an error response for each query for this datasource
   184→				rchan <- buildErrorResponses(err, subDTO.Queries)
   185→			}
   186→			return nil
   187→		})
   188→	}
   189→
   190→	if err := g.Wait(); err != nil {
   191→		return nil, err
   192→	}
   193→	close(rchan)
   194→	resp := backend.NewQueryDataResponse()
   195→	reqCtx := contexthandler.FromContext(ctx)
   196→	for result := range rchan {
   197→		for refId, dataResponse := range result.responses {
   198→			resp.Responses[refId] = dataResponse
   199→		}
   200→		if reqCtx != nil {
   201→			for k, v := range result.header {
   202→				for _, val := range v {
   203→					if !slices.Contains(reqCtx.Resp.Header().Values(k), val) {
   204→						reqCtx.Resp.Header().Add(k, val)
   205→					} else {
   206→						s.log.Warn("skipped duplicate response header", "header", k, "value", val)
   207→					}
   208→				}
   209→			}
   210→		}
   211→	}
   212→
   213→	return resp, nil
   214→}
   215→
   216→// buildErrorResponses applies the provided error to each query response in the list. These queries should all belong to the same datasource.
   217→func buildErrorResponses(err error, queries []*simplejson.Json) splitResponse {
   218→	er := backend.Responses{}
   219→	for _, query := range queries {
   220→		er[query.Get("refId").MustString("A")] = backend.DataResponse{
   221→			Error: err,
   222→		}
   223→	}
   224→	return splitResponse{er, http.Header{}}
   225→}
   226→
   227→func QueryData(ctx context.Context, log log.Logger, dscache datasources.CacheService, exprService *expr.Service, reqDTO dtos.MetricRequest, qsDatasourceClientBuilder dsquerierclient.QSDatasourceClientBuilder, headers map[string]string) (*backend.QueryDataResponse, error) {
   228→	s := &ServiceImpl{
   229→		log:                        log,
   230→		dataSourceCache:            dscache,
   231→		expressionService:          exprService,
   232→		dataSourceRequestValidator: validations.ProvideValidator(),
   233→		qsDatasourceClientBuilder:  qsDatasourceClientBuilder,
   234→		headers:                    headers,
   235→		concurrentQueryLimit:       16, // TODO: make it configurable
   236→	}
   237→
   238→	user, err := identity.GetRequester(ctx)
   239→	if err != nil {
   240→		return nil, err
   241→	}
   242→
   243→	return s.QueryDataNew(ctx, user, false, reqDTO)
   244→}
   245→
   246→// handleExpressions handles queries when there is an expression.
   247→func (s *ServiceImpl) handleExpressions(ctx context.Context, user identity.Requester, parsedReq *parsedRequest) (*backend.QueryDataResponse, error) {
   248→	exprReq := expr.Request{
   249→		Queries: []expr.Query{},
   250→	}
   251→
   252→	if user != nil { // for passthrough authentication, SSE does not authenticate
   253→		exprReq.User = user
   254→		exprReq.OrgId = user.GetOrgID()
   255→	}
   256→
   257→	for _, pq := range parsedReq.getFlattenedQueries() {
   258→		if pq.datasource == nil {
   259→			return nil, ErrMissingDataSourceInfo.Build(errutil.TemplateData{
   260→				Public: map[string]any{
   261→					"RefId": pq.query.RefID,
   262→				},
   263→			})
   264→		}
   265→
   266→		exprReq.Queries = append(exprReq.Queries, expr.Query{
   267→			JSON:          pq.query.JSON,
   268→			Interval:      pq.query.Interval,
   269→			RefID:         pq.query.RefID,
   270→			MaxDataPoints: pq.query.MaxDataPoints,
   271→			QueryType:     pq.query.QueryType,
   272→			DataSource:    pq.datasource,
   273→			TimeRange: expr.AbsoluteTimeRange{
   274→				From: pq.query.TimeRange.From,
   275→				To:   pq.query.TimeRange.To,
   276→			},
   277→		})
   278→	}
   279→
   280→	qdr, err := s.expressionService.TransformData(ctx, time.Now(), &exprReq) // use time now because all queries have absolute time range
   281→	if err != nil {
   282→		return nil, fmt.Errorf("expression request error: %w", err)
   283→	}
   284→	return qdr, nil
   285→}
   286→
   287→// handleQuerySingleDatasource handles one or more queries to a single datasource
   288→func (s *ServiceImpl) handleQuerySingleDatasource(ctx context.Context, user identity.Requester, parsedReq *parsedRequest) (*backend.QueryDataResponse, error) {
   289→	queries := parsedReq.getFlattenedQueries()
   290→	ds := queries[0].datasource
   291→	if err := s.dataSourceRequestValidator.Validate(ds, nil); err != nil {
   292→		return nil, datasources.ErrDataSourceAccessDenied
   293→	}
   294→
   295→	// ensure that each query passed to this function has the same datasource
   296→	for _, pq := range queries {
   297→		if ds.UID != pq.datasource.UID {
   298→			return nil, fmt.Errorf("all queries must have the same datasource - found %s and %s", ds.UID, pq.datasource.UID)
   299→		}
   300→	}
   301→
   302→	req := &backend.QueryDataRequest{
   303→		Headers: map[string]string{},
   304→		Queries: []backend.DataQuery{},
   305→	}
   306→
   307→	for _, q := range queries {
   308→		req.Queries = append(req.Queries, q.query)
   309→	}
   310→
   311→	qsDsClient, ok, err := s.qsDatasourceClientBuilder.BuildClient(ds.Type, ds.UID)
   312→	if err != nil {
   313→		return nil, err
   314→	}
   315→
   316→	if !ok { // single tenant flow
   317→		pCtx, err := s.pCtxProvider.GetWithDataSource(ctx, ds.Type, user, ds)
   318→		if err != nil {
   319→			return nil, err
   320→		}
   321→		req.PluginContext = pCtx
   322→		return s.pluginClient.QueryData(ctx, req)
   323→	} else { // query-service flow (single or multi tenant)
   324→		// transform request from backend.QueryDataRequest to k8s request
   325→		k8sReq, err := expr.ConvertBackendRequestToDataRequest(req)
