   287→// handleQuerySingleDatasource handles one or more queries to a single datasource
   288→func (s *ServiceImpl) handleQuerySingleDatasource(ctx context.Context, user identity.Requester, parsedReq *parsedRequest) (*backend.QueryDataResponse, error) {
   289→	queries := parsedReq.getFlattenedQueries()
   290→	ds := queries[0].datasource
   291→	if err := s.dataSourceRequestValidator.Validate(ds, nil); err != nil {
   292→		return nil, datasources.ErrDataSourceAccessDenied
   293→	}
   294→
   295→	// ensure that each query passed to this function has the same datasource
   296→	for _, pq := range queries {
   297→		if ds.UID != pq.datasource.UID {
   298→			return nil, fmt.Errorf("all queries must have the same datasource - found %s and %s", ds.UID, pq.datasource.UID)
   299→		}
   300→	}
   301→
   302→	req := &backend.QueryDataRequest{
   303→		Headers: map[string]string{},
   304→		Queries: []backend.DataQuery{},
   305→	}
   306→
   307→	for _, q := range queries {
   308→		req.Queries = append(req.Queries, q.query)
   309→	}
   310→
   311→	qsDsClient, ok, err := s.qsDatasourceClientBuilder.BuildClient(ds.Type, ds.UID)
   312→	if err != nil {
   313→		return nil, err
   314→	}
   315→
   316→	if !ok { // single tenant flow
   317→		pCtx, err := s.pCtxProvider.GetWithDataSource(ctx, ds.Type, user, ds)
   318→		if err != nil {
   319→			return nil, err
   320→		}
   321→		req.PluginContext = pCtx
   322→		return s.pluginClient.QueryData(ctx, req)
   323→	} else { // query-service flow (single or multi tenant)
   324→		// transform request from backend.QueryDataRequest to k8s request
   325→		k8sReq, err := expr.ConvertBackendRequestToDataRequest(req)
   326→		if err != nil {
   327→			return nil, err
   328→		}
   329→		return qsDsClient.QueryData(ctx, *k8sReq)
   330→	}
