    66→// NewQueryClientForPluginClient creates a client that delegates to the internal plugins.Client stack
    67→func newQueryClientForPluginClient(p plugins.Client, ctx *plugincontext.Provider, accessControl accesscontrol.AccessControl) clientapi.QueryDataClient {
    68→	return &pluginClient{
    69→		pluginClient: p,
    70→		pCtxProvider: ctx,
    71→		ac:           accessControl,
    72→	}
    73→}
    74→
    75→func NewDataSourceRegistryFromStore(pluginStore pluginstore.Store,
    76→	dataSourcesService datasources.DataSourceService,
    77→) query.DataSourceApiServerRegistry {
    78→	return &pluginRegistry{
    79→		pluginStore:        pluginStore,
    80→		dataSourcesService: dataSourcesService,
    81→	}
    82→}
    83→
    84→func (d *pluginClient) CanQueryDataSource(ctx context.Context, uid string) (bool, error) {
    85→	user, err := identity.GetRequester(ctx)
    86→	if err != nil {
    87→		return false, err
    88→	}
    89→
    90→	requiredScope := "datasources:uid:" + uid
    91→	evaluate := accesscontrol.EvalPermission(datasources.ActionQuery, requiredScope)
    92→	return d.ac.Evaluate(ctx, user, evaluate)
    93→}
    94→
    95→// this handles the special `--grafana--` data source
    96→func getGrafanaDataSourceSettings(ctx context.Context) (*backend.DataSourceInstanceSettings, error) {
    97→	user, err := identity.GetRequester(ctx)
    98→	if err != nil {
    99→		return nil, err
   100→	}
   101→
   102→	ds := grafanads.DataSourceModel(user.GetOrgID())
   103→
   104→	decryptFunc := func(ds *datasources.DataSource) (map[string]string, error) {
   105→		// we do not need to handle any secrets
   106→		return nil, nil
   107→	}
   108→
   109→	return adapters.ModelToInstanceSettings(ds, decryptFunc)
   110→}
   111→
   112→func (d *pluginClient) QueryData(ctx context.Context, req data.QueryDataRequest) (*backend.QueryDataResponse, error) {
   113→	queries, dsRef, err := data.ToDataSourceQueries(req)
   114→	if err != nil {
   115→		return nil, err
   116→	}
   117→	if dsRef == nil {
   118→		return nil, fmt.Errorf("expected single datasource request")
   119→	}
   120→
   121→	canQuery, err := d.CanQueryDataSource(ctx, dsRef.UID)
   122→	if err != nil {
   123→		return nil, err
   124→	}
   125→
   126→	if !canQuery {
   127→		return nil, k8sForbiddenError
   128→	}
   129→
   130→	var settings *backend.DataSourceInstanceSettings
   131→
   132→	// we need to special-case the "--grafana--" data source
   133→	if dsRef.UID == grafanads.DatasourceUID {
   134→		settings, err = getGrafanaDataSourceSettings(ctx)
   135→	} else {
   136→		// NOTE: this depends on uid unique across datasources
   137→		settings, err = d.pCtxProvider.GetDataSourceInstanceSettings(ctx, dsRef.UID)
   138→	}
   139→
   140→	if err != nil {
   141→		// there is no better way to differentiate between plugin-not-found and other-error
   142→		if errors.Is(err, datasources.ErrDataSourceNotFound) {
   143→			return nil, k8sNotFoundError
   144→		} else {
   145→			return nil, err
   146→		}
   147→	}
   148→
   149→	qdr := &backend.QueryDataRequest{
   150→		Queries: queries,
   151→	}
   152→	qdr.PluginContext, err = d.pCtxProvider.PluginContextForDataSource(ctx, settings)
   153→	if err != nil {
   154→		return nil, err
   155→	}
   156→
   157→	rsp, err := d.pluginClient.QueryData(ctx, qdr)
   158→	if err != nil {
   159→		return rsp, err
   160→	}
   161→	return rsp, err
   162→}
   163→
   164→// GetDatasourceAPI implements DataSourceRegistry.
   165→func (d *pluginRegistry) GetDatasourceGroupVersion(pluginId string) (schema.GroupVersion, error) {
   166→	d.pluginsMu.Lock()
   167→	defer d.pluginsMu.Unlock()
   168→
   169→	if d.plugins == nil {
   170→		err := d.updatePlugins()
   171→		if err != nil {
   172→			return schema.GroupVersion{}, err
   173→		}
   174→	}
   175→
   176→	var err error
   177→	gv, ok := d.apis[pluginId]
   178→	if !ok {
   179→		err = fmt.Errorf("no API found for id: %s", pluginId)
   180→	}
   181→	return gv, err
   182→}
   183→
   184→// GetDatasourcePlugins no namespace? everything that is available
   185→func (d *pluginRegistry) GetDatasourceApiServers(ctx context.Context) (*query.DataSourceApiServerList, error) {
   186→	d.pluginsMu.Lock()
   187→	defer d.pluginsMu.Unlock()
   188→
   189→	if d.plugins == nil {
   190→		err := d.updatePlugins()
   191→		if err != nil {
   192→			return nil, err
   193→		}
   194→	}
   195→
   196→	return d.plugins, nil
   197→}
   198→
   199→// This should be called when plugins change
   200→func (d *pluginRegistry) updatePlugins() error {
   201→	groupToPlugin := map[string]string{}
   202→	apis := map[string]schema.GroupVersion{}
   203→	result := &query.DataSourceApiServerList{
   204→		ListMeta: metav1.ListMeta{
   205→			ResourceVersion: fmt.Sprintf("%d", time.Now().UnixMilli()),
   206→		},
   207→	}
   208→
   209→	// TODO? only backend plugins
